Javascript.isReadOnly:
if (null != WP && null != WP.GetScreenProcess && null != WP.GetScreenProcess()) { 
				var localNumber = WPU.getValue("/params/param[@name='xml']/ds/Warrant/LocalNumber");
				if (localNumber == "" || localNumber == null) return true; }

Javascript.initialise:
var partyAgainstNumber = WPU.getValue("/params/param[@name='xml']/WarrantReturn/PartyAgainstNumber");
var def1Addr5 = WPU.getValue("/params/param[@name='xml']/ds/Warrant/Defendant1/Address/Line[5]");
var def2Addr5 = WPU.getValue("/params/param[@name='xml']/ds/Warrant/Defendant2/Address/Line[5]");
var partyAgainstAddr5 = "";
if(partyAgainstNumber == 1) {
	partyAgainstAddr5 = def1Addr5;
} else {
	partyAgainstAddr5 = def2Addr5; }
var otherPossessAddr5 = WPU.getValue("/params/param[@name='xml']/ds/ManageCase/OtherPossessionAddress/Address/Line[5]");
var possessAddr5 = "";
if(otherPossessAddr5 != "") {
	possessAddr5 = otherPossessAddr5;
} else {
	possessAddr5 = partyAgainstAddr5; }
Services.setValue(PossessAdLine5.dataBinding, possessAddr5);
